96	window.addEventListener('DOMContentLoaded', function() {
97	  // 검색 시스템 초기화
98	  const initResult = initSearch();
99	  if (initResult) {
100	    console.log('✅ 검색 시스템 초기화 완료');
101	  }
102	
103	  // 첫 번째 사용자로 렌더링
104	  renderMain();
105	
106	  // 검색 입력 이벤트
107	  const searchInput = document.getElementById('search-input');
108	  if (searchInput) {
