121	/**
122	 * 메인 콘텐츠 렌더링 (추천 차량)
123	 */
124	function renderMain() {
125	  const customer = DATA[currentUser];
126	  const recommendedSection = document.getElementById('recommended-section');
127	
128	  if (!recommendedSection) return;
129	
130	  // 배너
131	  const bannerHtml = `
132	    <div class="banner" style="background: ${customer.bannerBg};">
133	      <div class="banner-txt">
134	        <h2>${customer.bannerText.title}</h2>
135	        <p>${customer.bannerText.subtitle}</p>
136	        <span class="banner-badge">${customer.bannerText.badge}</span>
137	      </div>
138	      <div class="banner-deco">🚗</div>
139	    </div>
140	  `;
141	
142	  // 추천 차량 섹션
143	  const carGridHtml = `
144	    <div class="sec-label">
145	      <span class="badge badge-${currentUser.toLowerCase()}">${currentUser}사용자</span>
146	      <span class="sec-title">추천 <span style="color: ${currentUser === 'A' ? '#1a56db' : '#28c76f'}">차량</span></span>
147	    </div>
148	    <div class="car-grid">
149	      ${customer.recommendedCars.map(carKey => {
150	        const car = getCarFromAllResults(carKey);
151	        if (!car) return '';
152	        return `
153	          <div class="car-card" onclick="viewDetails('${carKey}')">
154	            <div class="car-img">
155	              <img src="${CAR_IMGS[carKey]}" alt="${car.name}">
156	              <span class="img-tag ${car.tagC}">${car.tag}</span>
157	              <div class="img-btns">
158	                <button class="ib" onclick="viewDetails('${carKey}'); event.stopPropagation();">상세</button>
159	                <button class="ib" onclick="selectProduct('${carKey}'); event.stopPropagation();">선택</button>
160	              </div>
161	            </div>
162	            <div class="car-info">
163	              <div class="car-brand">${car.brand}</div>
164	              <div class="car-name">${car.name}</div>
165	              <div class="car-spec">${car.spec}</div>
166	              <div class="price-row">
167	                <span class="price" style="color: ${currentUser === 'A' ? '#1a56db' : '#28c76f'}">${car.price}</span>
168	              </div>
169	              <div class="price-sub">${car.sub}</div>
170	            </div>
171	          </div>
172	        `;
173	      }).join('')}
174	    </div>
175	  `;
176	
177	  recommendedSection.innerHTML = bannerHtml + carGridHtml;
178	
179	  // 사이드바 업데이트
180	  updateSidebar();
181	
182	  // 검색 컨테이너 숨기기
183	  const resultsContainer = document.getElementById('search-results-container');
184	  if (resultsContainer) {
185	    resultsContainer.style.display = 'none';
186	  }
187	}
