189	/**
190	 * 사이드바 업데이트
191	 */
192	function updateSidebar() {
193	  const customer = DATA[currentUser];
194	
195	  // 색상 정의
196	  const colorA = '#1a56db';
197	  const colorB = '#28c76f';
198	  const color = currentUser === 'A' ? colorA : colorB;
199	  const bgGradient = currentUser === 'A'
200	    ? 'linear-gradient(135deg,#4f8ef7,#1a56db)'
201	    : 'linear-gradient(135deg,#48d98a,#28c76f)';
202	
203	  document.getElementById('sbAvatar').textContent = customer.avatar;
204	  document.getElementById('sbName').textContent = customer.name;
205	  document.getElementById('sbName').style.color = color;
206	  document.getElementById('sbMeta').textContent = customer.meta;
207	  document.getElementById('sbInterest').textContent = customer.interest;
208	  document.getElementById('sbInterest').style.color = color;
209	
210	  document.getElementById('crScore').textContent = customer.creditScore;
211	  document.getElementById('crScore').style.color = color;
212	  document.getElementById('crGrade').textContent = customer.creditGrade;
213	  document.getElementById('crLoan').textContent = customer.loanMax;
214	  document.getElementById('crLoan').style.color = color;
215	  document.getElementById('curCar').textContent = customer.currentCar;
216	
217	  // 고객 여정 초기화 (첫 탭: 검색)
218	  updateJourneyList('검색');
219	
220	  // 선택 드롭다운 업데이트
221	  document.getElementById('selA').value = currentUser;
222	}
