224	/**
225	 * 고객 여정 리스트 업데이트
226	 */
227	function updateJourneyList(tabName) {
228	  const customer = DATA[currentUser];
229	  const jList = document.getElementById('jList');
230	  const items = customer.journey[tabName] || [];
231	
232	  jList.innerHTML = items.map(item => `
233	    <div class="j-item">
234	      <div class="j-thumb">
235	        ${['검색', '클릭', '찜', '담기', '구매'].indexOf(tabName) + 1}
236	      </div>
237	      <div>
238	        <div class="j-tag">${item.tag}</div>
239	        <div class="j-name">${item.name}</div>
240	        <div class="j-cat">${item.cat}</div>
241	      </div>
242	    </div>
243	  `).join('');
244	}
