250	/**
251	 * A 사용자 선택
252	 */
253	function onSelectA(value) {
254	  currentUser = value;
255	  if (value === 'C') {
256	    showGuestView();
257	  } else {
258	    showMemberView();
259	    renderMain();
260	  }
261	}
262	
263	/**
264	 * B 사용자 선택
265	 */
266	function onSelectB(value) {
267	  compareUser = value;
268	}
269	
270	/**
271	 * 적용 버튼
272	 */
273	function apply() {
274	  if (compareUser !== 'none') {
275	    alert(`${currentUser}사용자와 ${compareUser}사용자를 비교하는 기능은 추후 추가됩니다.`);
276	  }
277	  renderMain();
278	}
279	
280	/**
281	 * 이전 사용자
282	 */
283	function prevUser() {
284	  currentUser = currentUser === 'A' ? 'B' : 'A';
285	  renderMain();
286	}
287	
288	/**
289	 * 다음 사용자
290	 */
291	function nextUser() {
292	  currentUser = currentUser === 'A' ? 'B' : 'A';
293	  renderMain();
294	}
