308	/**
309	 * 회원 뷰 표시
310	 */
311	function showMemberView() {
312	  const memberSidebar = document.getElementById('memberSidebar');
313	  const guestSidebar = document.getElementById('guestSidebar');
314	  if (memberSidebar) memberSidebar.style.display = '';
315	  if (guestSidebar) guestSidebar.style.display = 'none';
316	}
317	
318	/**
319	 * 비회원 뷰 표시
320	 */
321	function showGuestView() {
322	  const memberSidebar = document.getElementById('memberSidebar');
323	  const guestSidebar = document.getElementById('guestSidebar');
324	  if (memberSidebar) memberSidebar.style.display = 'none';
325	  if (guestSidebar) guestSidebar.style.display = 'flex';
326	  renderGuestMain();
327	}
