329	/**
330	 * 비회원 메인 콘텐츠 렌더링
331	 */
332	function renderGuestMain() {
333	  const section = document.getElementById('recommended-section');
334	  if (!section) return;
335	
336	  // 비회원용 배너 + 인기차 목록
337	  const html = `
338	    <div class="banner" onclick="openChat()" style="background: linear-gradient(120deg,#1e3a5f,#2563eb 60%,#60a5fa); cursor:pointer;">
339	      <div>
340	        <h2>나만의 맞춤 신차,<br>AI가 찾아드립니다</h2>
341	        <p>몇 가지 질문으로 고객님께 딱 맞는<br>차량을 바로 추천해드려요.</p>
342	        <span class="banner-cta">✨ AI 추천 받기 →</span>
343	      </div>
344	      <div class="banner-deco">🤖</div>
345	      <div class="banner-hint">👆 클릭하면 AI 상담을 시작합니다</div>
346	    </div>
347	    <div class="sec-hdr">
348	      <span style="font-size:15px">✨</span>
349	      <h3>요즘 주목 받는 신차 안내</h3>
350	    </div>
351	    <div class="prod-grid" id="popularGrid"></div>
352	  `;
353	
354	  section.innerHTML = html;
355	  renderPopularCars();
356	
357	  // 검색 결과 숨기기
358	  const resultsContainer = document.getElementById('search-results-container');
359	  if (resultsContainer) {
360	    resultsContainer.style.display = 'none';
361	  }
362	}
363	
364	/**
365	 * 인기 차량 목록 렌더링
366	 */
367	function renderPopularCars() {
368	  const grid = document.getElementById('popularGrid');
369	  if (!grid || typeof SEARCH_RESULTS === 'undefined') return;
370	
371	  // SEARCH_RESULTS의 모든 차량을 모아서 표시
372	  const allCars = [];
373	  for (const resultId in SEARCH_RESULTS) {
374	    SEARCH_RESULTS[resultId].cars.forEach(car => {
375	      // 중복 제거
376	      if (!allCars.find(c => c.img === car.img)) {
377	        allCars.push(car);
378	      }
379	    });
380	  }
381	
382	  grid.innerHTML = allCars.slice(0, 8).map(car => `
383	    <div class="prod-card">
384	      <div class="pc-img">
385	        <img src="${CAR_IMGS[car.img]}" alt="${car.name}" style="max-width:100%; max-height:100%; object-fit:contain;">
386	        <span class="pc-tag ${car.tagC}">${car.tag}</span>
387	        <div class="pc-btns">
388	          <button class="pc-btn" onclick="viewDetails('${car.img}')">상세</button>
389	          <button class="pc-btn" onclick="selectProduct('${car.img}')">선택</button>
390	        </div>
391	      </div>
392	      <div class="pc-info">
393	        <div class="pc-brand">${car.brand}</div>
394	        <div class="pc-name">${car.name}</div>
395	        <div class="pc-spec">${car.spec}</div>
396	        <div class="pc-price">${car.price}</div>
397	      </div>
398	    </div>
399	  `).join('');
400	}
