415	/**
416	 * 탭 전환 (고객 여정)
417	 */
418	function setTab(element, tabName) {
419	  // 기존 활성 탭 제거
420	  const tabs = document.querySelectorAll('.jtab');
421	  tabs.forEach(t => t.classList.remove('on'));
422	
423	  // 새 탭 활성화
424	  element.classList.add('on');
425	
426	  // 고객 여정 리스트 업데이트
427	  updateJourneyList(tabName);
428	}
